using NustLmsApi.Standard;
using NustLmsApi.Standard.Http.Client.Proxy;

namespace ConsoleApp;

var client = new NustLmsApiClient.Builder()
.HttpClientConfig(config => config
    .Proxy(new ProxyConfigurationBuilder("http://localhost")
            .Port(8080)
            .Tunnel(false)
            .Auth("user", "pass")
    )
)
.Build();

try
{
    ApiResponse<ExampleType> response = await client.ExampleController.GetExampleType(body);
    Console.WriteLine($"Success! Result: {response.Data}");
    Console.WriteLine($"Status Code: {response.StatusCode}");
}
catch (ApiException e)
{
    Console.WriteLine($"Error: {e.Message}");
